const b = $input.first().json.body || $input.first().json;
const instagramUrls = (b.instagram || []).filter(Boolean);
const instagramHandles = instagramUrls.map(u => {
  return String(u).replace(/^https?:\/\/(www\.)?instagram\.com\//, '').replace(/\/$/, '').split('/')[0].toLowerCase();
}).filter(Boolean);
const tiktokProfiles = (b.tiktok || []).map(u => {
  const m = String(u).match(/@([\w.]+)/);
  return m ? '@' + m[1] : u;
}).filter(Boolean);
const facebookUrls = (b.facebook || []).filter(Boolean);
return [{ instagramUrls, instagramHandles, tiktokProfiles, facebookUrls }];

const scan = (obj) => {
  if (!obj || typeof obj !== 'object') return 0;
  const known = ['followersCount','follower_count','ownerFollowersCount','ownerFollowerCount','fans','followers'];
  for (const f of known) { if (obj[f] > 0) return obj[f]; }
  if (obj.edge_followed_by?.count > 0) return obj.edge_followed_by.count;
  for (const k of Object.keys(obj)) {
    const kl = k.toLowerCase();
    if ((kl.includes('follower') || kl === 'fans') && !kl.includes('following') && typeof obj[k] === 'number' && obj[k] > 0) return obj[k];
  }
  return 0;
};

// --- Instagram (profile scraper returns array at root via HTTP Request) ---
const igMap = {};
const igDebug = {};
const igProfiles = [];
for (const item of $('IG Scraper').all()) {
  const d = item.json;
  if (Array.isArray(d)) { igProfiles.push(...d); }
  else { igProfiles.push(d); }
}
for (const d of igProfiles) {
  const u = (d.username || d.ownerUsername || '').toLowerCase();
  if (!u) continue;
  const f = scan(d) || scan(d.owner) || scan(d.user) || 0;
  igMap[u] = f;
  igDebug[u] = {
    foundFollowers: f,
    followersCount: d.followersCount,
    postsCount: d.postsCount,
    isVerified: d.isVerified,
    allRootKeys: Object.keys(d)
  };
}

// --- TikTok ---
const ttMap = {};
const ttDebug = {};
for (const item of $('TT Scraper').all()) {
  const d = item.json;
  const u = (d.authorMeta?.name || d.authorUniqueId || '').toLowerCase();
  if (!u) continue;
  const f = d.authorMeta?.fans || d.authorStats?.followerCount || scan(d.authorMeta) || 0;
  ttMap[u] = f;
  ttDebug[u] = {
    foundFollowers: f,
    authorMetaFans: d.authorMeta?.fans,
    authorMetaKeys: d.authorMeta ? Object.keys(d.authorMeta) : []
  };
}

const followers = { ...igMap, ...ttMap };
return [{ followers, debug: { instagram: igDebug, tiktok: ttDebug } }];
